// Cross Shape
function CrossShape() {
	mxActor.call(this);
}

mxUtils.extend(CrossShape, mxActor);

CrossShape.prototype.size = 0.2;

CrossShape.prototype.redrawPath = function (c, x, y, w, h) {
	var m = Math.min(h, w);
	var size = Math.max(0, Math.min(m, m * parseFloat(mxUtils.getValue(this.style, 'size', this.size))));
	var t = (h - size) / 2;
	var b = t + size;
	var l = (w - size) / 2;
	var r = l + size;

	c.moveTo(0, t);
	c.lineTo(l, t);
	c.lineTo(l, 0);
	c.lineTo(r, 0);
	c.lineTo(r, t);
	c.lineTo(w, t);
	c.lineTo(w, b);
	c.lineTo(r, b);
	c.lineTo(r, h);
	c.lineTo(l, h);
	c.lineTo(l, b);
	c.lineTo(0, b);
	c.close();
	c.end();
};

mxCellRenderer.registerShape('cross', CrossShape);

